import requests

def refresh_oauth2_token(token_url: str, refresh_token: str, client_id: str, client_secret: str = None) -> dict | None:
    headers = {
        'Content-Type': 'application/x-www-form-urlencoded'
    }

    data = {
        'grant_type': 'refresh_token',
        'refresh_token': refresh_token,
        'client_id': client_id,
    }

    if client_secret:
        data['client_secret'] = client_secret

    try:
        response = requests.post(token_url, data=data, headers=headers)
        response.raise_for_status()
        return response.json()
    except (requests.exceptions.HTTPError, requests.exceptions.ConnectionError, requests.exceptions.Timeout, requests.exceptions.RequestException) as e:
        return None
    except requests.exceptions.JSONDecodeError:
        return None
